// Simply pass through the search query from the previous node
const result = {};

if (items[0].json.searchQuery) {
  result.searchQuery = items[0].json.searchQuery;
} else {
  result.searchQuery = "No valid search query found";
}

return {json: result};

// The message is in item.chatInput based on your debug output
const item = items[0].json;
let message = '';

// Specifically check for chatInput field first
if (item.chatInput) {
  message = item.chatInput;
} else if (item.messageText) {
  message = item.messageText;
} else if (item.text) {
  message = item.text;
} else if (item.message) {
  message = item.message;
} else if (item.content) {
  message = item.content;
} else {
  message = '';
}

const bookInfo = {};

// Only proceed with parsing if we have a message
if (message && typeof message === 'string') {
  if (message.toLowerCase().includes(" by ")) {
    const parts = message.toLowerCase().split(" by ");
    // Remove question marks, periods, and other ending punctuation
    bookInfo.title = parts[0].replace(/can i get information about|info on|details for/gi, "").trim();
    bookInfo.author = parts[1].replace(/\?|\.|\!|\,$/, "").trim();

    // Format for Google Drive - clean up any unwanted punctuation
    bookInfo.searchQuery = `${bookInfo.title} - ${bookInfo.author}`;
  } else if (message.includes(" - ")) {
    // Handle already formatted as "Title - Author"
    const parts = message.split(" - ");
    bookInfo.title = parts[0].trim();
    bookInfo.author = parts[1].replace(/\?|\.|\!|\,$/, "").trim();
    bookInfo.searchQuery = `${bookInfo.title} - ${bookInfo.author}`;
  } else {
    // Treat the whole message as a search term
    bookInfo.searchTerm = message;
    bookInfo.searchQuery = message.replace(/\?|\.|\!|\,$/, "").trim();
  }
} else {
  bookInfo.searchTerm = "No valid message found";
  bookInfo.searchQuery = "No valid message found";
}

return {json: bookInfo};

const content = $json.content || "";
const characterCount = content.length;
const wordCount = Math.floor(characterCount / 5); // Average word length assumption

return [{
  json: {
    ...$json,
    characterCount,
    estimatedWordCount: wordCount
  }
}];

const metadata   = $json.output || $json;
const safeCount  = metadata.wordCount     || 0;
const spiceLevel = metadata.spiceLevel    || 0;
// ← NEW: grab subtitle, defaulting to blank
const subtitle   = metadata.subtitle      || '';

const formatList         = arr => arr?.map(i => `• ${i}`).join('\n')      || '';
const formatInlineList   = arr => arr?.join(', ')                         || '';
const formatNumberedList = arr => arr?.map((i, idx) => `${idx+1}. ${i}`).join('\n') || '';

const formatted = `
TITLE: ${metadata.bookTitle}
SUBTITLE: ${subtitle}
SERIES NAME & NUMBER: ${metadata.seriesInfo}

STANDALONE OR SERIES HOOK: ${metadata.standaloneSeries}

RELEASE DATE: 

WORD COUNT: ${safeCount.toLocaleString()}

SPICE LEVEL: ${'🌶️'.repeat(spiceLevel)} (Level ${spiceLevel})

TROPES:
${formatList(metadata.tropes)}

UNIVERSAL FANTASIES:
${formatList(metadata.universalFantasies)}

READER POSITIONING:

• Core Reader Fantasy: ${metadata.coreReaderFantasy}
• Emotional Vibe: ${metadata.emotionalVibe}
• Reader Promises: ${metadata.readerPromises}
• SEO Keywords: ${formatInlineList(metadata.seoKeywords)}
• Hashtags: ${formatInlineList(metadata.hashtags)}

AMAZON KEYWORDS:
${formatNumberedList(metadata.amazonKeywords)}
`;

return [{
  json: {
    ...metadata,
    // ← NEW: ensure subtitle is passed through
    subtitle,
    formattedText: formatted.trim()
  }
}];

